const envelope = $input.first().json;
const input = envelope.body ?? envelope;
const taskTitle = input.task?.title ?? 'Unknown task';
const projectName = input.project?.name ?? 'Unknown project';
const eventType = input.eventType ?? 'unknown';
return [{
  json: {
    ok: true,
    receivedAt: new Date().toISOString(),
    summary: `Workflow received ${eventType} for ${taskTitle} in ${projectName}.`,
    eventType,
    project: input.project ?? null,
    task: input.task ?? null,
    source: input.source ?? 'estala-project-manager',
    nextStep: 'Attach email, Slack, CRM, or database actions after this node.'
  }
}];
